SELECT AVG(producao_mil_ton) AS media_producao_soja
FROM conab_serie_historica_soja
WHERE LOWER(safra) LIKE '%1970%' OR LOWER(safra) LIKE '%1980%' OR LOWER(safra) LIKE '%1990%' OR LOWER(safra) LIKE '%2000%' OR LOWER(safra) LIKE '%2010%' OR LOWER(safra) LIKE '%2020%';

SELECT valor AS produção_2024_santacatarina
FROM ibge_silvicultura_madeira_tora
WHERE LOWER(localidade) = 'santa catarina' AND ano = 2024;
